class Solution:
    def shortestSequence(self, rolls, k):
        # Independent approach: count maximal disjoint blocks that contain all k faces
        # by re-scanning the remaining suffix from each block boundary.
        n = len(rolls)
        i = 0
        rounds = 0
        while i < n:
            present = [False] * (k + 1)
            need = k
            while i < n and need > 0:
                v = rolls[i]
                if not present[v]:
                    present[v] = True
                    need -= 1
                i += 1
            if need == 0:
                rounds += 1
            else:
                break
        return rounds + 1

